import numpy as np

def sigmoid(x):
    return 1.0 / (1.0 + np.exp(-x))      # 用指数把输出压到 0 到 1，适合概率语义

def relu(x):
    return np.maximum(x, 0.0)            # 直接砍掉负区，换来便宜且稳定的正区梯度

def gelu(x):
    c = np.sqrt(2.0 / np.pi)
    return 0.5 * x * (1 + np.tanh(c * (x + 0.044715 * x**3)))
    # 用 tanh 近似是因为精确 CDF 太慢，训练里更看重平滑门控和效率平衡

x = np.array([-2.0, 0.5, 2.0])
print(sigmoid(x))
print(relu(x))
print(gelu(x))
